#pragma once
#include "card.h"
#include <cstdint>

// ---------------------------------------------------------------------------
// Two Plus Two 7-card hand evaluator
// Requires data/handranks.dat (generated by tools/gen_lookup_table.cpp)
//
// evaluate_7cards() returns a rank in [1, 7462]:
//   1     = worst high card
//   7462  = Royal Flush
//   Higher value always beats lower value.
// ---------------------------------------------------------------------------

// Load lookup table from file. Call once at startup.
// Returns true on success.
bool hand_eval_init(const char* path = "data/handranks.dat");

// Evaluate best 5-card hand from exactly 7 cards.
uint16_t evaluate_7cards(Card c0, Card c1, Card c2,
                          Card c3, Card c4, Card c5, Card c6);

// Evaluate best hand from hole + community (n_comm in 0,3,4,5)
uint16_t evaluate_best(Card h0, Card h1,
                       const Card* community, int n_comm);

// Precompute best hand ranks for all players at all streets in one pass.
// out_ranks[player][street]: 0=preflop(0), 1=flop, 2=turn, 3=river
// hole_cards: [num_players][2], community: [5]
void precompute_ranks(const Card* hole_cards,
                      const Card* community,
                      int num_players,
                      uint16_t* out_ranks);

// Hand category from rank value
const char* hand_category(uint16_t rank);
